Create a new hook that registers a global `keydown` listener for the `?` key to toggle the shortcuts reference panel.

## Step 1: Create the hook

File: `apps/client/src/layers/features/shortcuts/model/use-shortcuts-panel.ts`

Create the directories `apps/client/src/layers/features/shortcuts/model/` first.

```typescript
import { useEffect } from 'react';
import { useAppStore } from '@/layers/shared/model';

/**
 * Register the `?` key handler that toggles the shortcuts reference panel.
 *
 * Guards against firing in text inputs (INPUT, TEXTAREA, contentEditable).
 * The `?` key is `Shift+/` — `e.key === '?'` captures it without checking shiftKey.
 */
export function useShortcutsPanel(): void {
  const toggleShortcutsPanel = useAppStore((s) => s.toggleShortcutsPanel);

  useEffect(() => {
    const handler = (e: KeyboardEvent) => {
      const target = e.target as HTMLElement;
      const inInput =
        target.tagName === 'INPUT' ||
        target.tagName === 'TEXTAREA' ||
        target.isContentEditable;

      if (e.key === '?' && !inInput) {
        e.preventDefault();
        toggleShortcutsPanel();
      }
    };

    document.addEventListener('keydown', handler);
    return () => document.removeEventListener('keydown', handler);
  }, [toggleShortcutsPanel]);
}
```

This pattern follows `use-global-palette.ts` exactly: `useEffect` + `document.addEventListener('keydown')` + cleanup function.

Key details:
- The `?` key is `Shift+/` on US keyboards. Using `e.key === '?'` handles this correctly without needing to check `e.shiftKey`.
- Guards against firing when the user is typing in an input, textarea, or contentEditable element.
- Uses `e.preventDefault()` to prevent the `?` character from being typed into any accidentally focused element.
- The hook takes no parameters and returns nothing — it's a side-effect-only hook.

## Step 2: Write unit tests

File: `apps/client/src/layers/features/shortcuts/__tests__/use-shortcuts-panel.test.ts`

```typescript
/**
 * @vitest-environment jsdom
 */
import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest';
import { renderHook } from '@testing-library/react';
import { useAppStore } from '@/layers/shared/model';
import { useShortcutsPanel } from '../model/use-shortcuts-panel';

describe('useShortcutsPanel', () => {
  beforeEach(() => {
    useAppStore.setState({ shortcutsPanelOpen: false });
  });

  afterEach(() => {
    vi.restoreAllMocks();
  });

  it('toggles shortcutsPanelOpen when ? is pressed', () => {
    renderHook(() => useShortcutsPanel());

    document.dispatchEvent(new KeyboardEvent('keydown', { key: '?' }));
    expect(useAppStore.getState().shortcutsPanelOpen).toBe(true);

    document.dispatchEvent(new KeyboardEvent('keydown', { key: '?' }));
    expect(useAppStore.getState().shortcutsPanelOpen).toBe(false);
  });

  it('does NOT toggle when ? is pressed inside an INPUT', () => {
    renderHook(() => useShortcutsPanel());

    const input = document.createElement('input');
    document.body.appendChild(input);
    input.focus();

    const event = new KeyboardEvent('keydown', { key: '?', bubbles: true });
    Object.defineProperty(event, 'target', { value: input });
    document.dispatchEvent(event);

    expect(useAppStore.getState().shortcutsPanelOpen).toBe(false);
    document.body.removeChild(input);
  });

  it('does NOT toggle when ? is pressed inside a TEXTAREA', () => {
    renderHook(() => useShortcutsPanel());

    const textarea = document.createElement('textarea');
    document.body.appendChild(textarea);
    textarea.focus();

    const event = new KeyboardEvent('keydown', { key: '?', bubbles: true });
    Object.defineProperty(event, 'target', { value: textarea });
    document.dispatchEvent(event);

    expect(useAppStore.getState().shortcutsPanelOpen).toBe(false);
    document.body.removeChild(textarea);
  });

  it('does NOT toggle when ? is pressed inside a contentEditable element', () => {
    renderHook(() => useShortcutsPanel());

    const div = document.createElement('div');
    div.contentEditable = 'true';
    document.body.appendChild(div);
    div.focus();

    const event = new KeyboardEvent('keydown', { key: '?', bubbles: true });
    Object.defineProperty(event, 'target', { value: div });
    document.dispatchEvent(event);

    expect(useAppStore.getState().shortcutsPanelOpen).toBe(false);
    document.body.removeChild(div);
  });
});
```

